/**
 * Few-shot worked examples — the GeoFM-proven booster (their GPT-4 went
 * 0.628 → 0.661 with few-shot; we run zero-shot everywhere else).
 *
 * One MINIATURE synthetic scene (2 buildings — ~600 tokens vs 6.7k for a real
 * scene) rendered in the arm's own format, with two fully worked Q→A
 * demonstrations (containment + the empty-set coverage case). The scene is
 * generated by the real synthetic generator (format-faithful) and the answers
 * are computed by the oracle — nothing hand-authored can drift or be wrong.
 * No leakage: the example scene exists only here; test scenes are real-OSM.
 */

import type { ArmId } from "./engine";
import { closuresInsideBuildings, coverageGapBuildings } from "./oracle";
import { pointInPolygon } from "./geo";
import { toJSON, toWKT } from "./representations";
import { toTextMapV2 } from "./textmap";
import { makeSyntheticScene, type Scene } from "./scene";

let cache: Partial<Record<ArmId, string>> | null = null;

function miniScene(): Scene {
  return makeSyntheticScene({
    id: "fewshot-mini",
    seed: 999, // never used by any test run (tests use 1000+)
    blocksX: 2,
    blocksY: 1,
    plant: { closureInBuilding: true, closureOnStreet: true },
  });
}

function insideOf(scene: Scene, equipmentId: string): string {
  const e = scene.equipment.find((x) => x.id === equipmentId);
  if (!e) return "none";
  const b = scene.buildings.find((bl) => pointInPolygon(e.position, bl.footprint));
  return b?.id ?? "none";
}

function workedQA(scene: Scene, arm: ArmId): string {
  const inside = closuresInsideBuildings(scene);
  const gaps = coverageGapBuildings(scene);
  const eqLines = scene.equipment
    .filter((e) => e.kind !== "co")
    .map((e) => `${e.id} -> inside=${insideOf(scene, e.id)}`)
    .join("; ");

  const containmentReasoning =
    arm === "textmap2" || arm === "textmap2np" || arm === "textmap"
      ? `Check every equipment row in the LEGEND and read its inside= field: ${eqLines}. ` +
        "Exactly the items whose inside= names a building are inside one."
      : "Test each equipment position against each building polygon ring (point-in-polygon): " +
        `${eqLines}. Include exactly the items whose point falls inside a ring.`;

  const coverageReasoning =
    arm === "textmap2" || arm === "textmap2np" || arm === "textmap"
      ? "Check every building's d_closure= value in the LEGEND. A gap exists ONLY where " +
        "d_closure > 35. " +
        (gaps.length === 0
          ? "Here every building has a closure within 35m — so the correct answer is the " +
            "EMPTY array. An empty answer is a real, common answer."
          : `Here ${gaps.join(", ")} exceed 35m.`)
      : "For each building, compute the distance to its nearest closure. " +
        (gaps.length === 0
          ? "Here every building has a closure within 35m — the correct answer is the EMPTY " +
            "array. An empty answer is a real, common answer."
          : `Here ${gaps.join(", ")} exceed 35m.`);

  return (
    `EXAMPLE QUESTION 1: List the ids of every equipment item whose point lies INSIDE a ` +
    `building footprint. Fill \`equipmentIds\` (empty array if none).\n` +
    `EXAMPLE REASONING: ${containmentReasoning}\n` +
    `EXAMPLE ANSWER: {"equipmentIds": ${JSON.stringify(inside)}}\n\n` +
    `EXAMPLE QUESTION 2: Is there any building with NO closure within 35m of it (a coverage ` +
    `gap)? Fill \`buildingIds\` with every such building (empty array if none).\n` +
    `EXAMPLE REASONING: ${coverageReasoning}\n` +
    `EXAMPLE ANSWER: {"buildingIds": ${JSON.stringify(gaps)}}`
  );
}

/** The few-shot preamble for an arm ("" when the arm can't be demonstrated —
 *  the image arm has no inline-demonstrable form). */
export function fewshotFor(arm: ArmId): string {
  if (arm === "image" || arm === "verdict" || arm === "ascii") return "";
  if (!cache) cache = {};
  const hit = cache[arm];
  if (hit !== undefined) return hit;

  const scene = miniScene();
  const rep =
    arm === "json"
      ? toJSON(scene)
      : arm === "wkt"
        ? toWKT(scene)
        : toTextMapV2(scene, { protocol: false }); // mini demo: data only, keep it short

  const text =
    "WORKED EXAMPLE (a DIFFERENT, smaller scene — study the method, then answer only " +
    "about the real scene below):\n" +
    `${rep}\n\n${workedQA(scene, arm)}\n` +
    "END OF WORKED EXAMPLE.\n\n";
  cache[arm] = text;
  return text;
}
